class SAMLResponseParser:
    """Parses and validates SAML Response XML."""

    def __init__(self, saml_response_b64):
        self.raw_response = base64.b64decode(saml_response_b64)
        self.xml_string = self.raw_response.decode('utf-8')
        self.root = ET.fromstring(self.xml_string)
        self.errors = []

    def _find(self, element, path):
        """Find element using SAML namespaces."""
        return element.find(path, SAML_NAMESPACES)

    def _findall(self, element, path):
        """Find all elements using SAML namespaces."""
        return element.findall(path, SAML_NAMESPACES)

    def validate_response_status(self):
        """Validate that the SAML response status is Success."""
        status = self._find(self.root, './/samlp:Status/samlp:StatusCode')
        if status is None:
            self.errors.append('No StatusCode element found in SAML response.')
            return False

        status_value = status.get('Value', '')
        if 'Success' not in status_value:
            status_message_elem = self._find(self.root, './/samlp:Status/samlp:StatusMessage')
            status_message = status_message_elem.text if status_message_elem is not None else 'Unknown error'
            self.errors.append(f'SAML response status is not Success: {status_value}. Message: {status_message}')
            return False

        return True

    def validate_destination(self):
        """Validate the Destination attribute matches our ACS URL."""
        destination = self.root.get('Destination', '')
        if destination and destination != SAML_CONFIG['sp_acs_url']:
            self.errors.append(
                f'Destination mismatch. Expected: {SAML_CONFIG["sp_acs_url"]}, Got: {destination}'
            )
            return False
        return True

    def validate_issuer(self):
        """Validate the Issuer matches expected IdP entity ID."""
        issuer_elem = self._find(self.root, 'saml:Issuer')
        if issuer_elem is None:
            self.errors.append('No Issuer element found in SAML response.')
            return False

        issuer = issuer_elem.text
        if issuer != SAML_CONFIG['idp_entity_id']:
            self.errors.append(
                f'Issuer mismatch. Expected: {SAML_CONFIG["idp_entity_id"]}, Got: {issuer}'
            )
            return False
        return True

    def get_assertion(self):
        """Extract the Assertion element from the response."""
        assertion = self._find(self.root, './/saml:Assertion')
        if assertion is None:
            self.errors.append('No Assertion element found in SAML response.')
            return None
        return assertion

    def validate_assertion_conditions(self, assertion):
        """Validate assertion time conditions."""
        conditions = self._find(assertion, 'saml:Conditions')
        if conditions is None:
            # Conditions are optional but recommended
            return True

        now = datetime.utcnow()

        not_before = conditions.get('NotBefore')
        if not_before:
            not_before_dt = datetime.fromisoformat(not_before.replace('Z', '+00:00')).replace(tzinfo=None)
            # Allow 5 minutes clock skew
            if now < not_before_dt - timedelta(minutes=5):
                self.errors.append(
                    f'Assertion is not yet valid. NotBefore: {not_before}, Now: {now.isoformat()}'
                )
                return False

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            not_on_or_after_dt = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00')).replace(tzinfo=None)
            # Allow 5 minutes clock skew
            if now >= not_on_or_after_dt + timedelta(minutes=5):
                self.errors.append(
                    f'Assertion has expired. NotOnOrAfter: {not_on_or_after}, Now: {now.isoformat()}'
                )
                return False

        # Validate AudienceRestriction
        audience_restriction = self._find(conditions, 'saml:AudienceRestriction')
        if audience_restriction is not None:
            audiences = self._findall(audience_restriction, 'saml:Audience')
            audience_values = [a.text for a in audiences if a.text]
            if SAML_CONFIG['sp_entity_id'] not in audience_values:
                self.errors.append(
                    f'SP entity ID not in audience. Expected: {SAML_CONFIG["sp_entity_id"]}, Got: {audience_values}'
                )
                return False

        return True

    def validate_assertion_subject(self, assertion):
        """Validate the Subject element and SubjectConfirmation."""
        subject = self._find(assertion, 'saml:Subject')
        if subject is None:
            self.errors.append('No Subject element found in Assertion.')
            return False

        # Check SubjectConfirmation
        subject_confirmation = self._find(subject, 'saml:SubjectConfirmation')
        if subject_confirmation is not None:
            method = subject_confirmation.get('Method', '')
            if 'bearer' not in method.lower():
                self.errors.append(f'Unexpected SubjectConfirmation method: {method}')
                return False

            conf_data = self._find(subject_confirmation, 'saml:SubjectConfirmationData')
            if conf_data is not None:
                recipient = conf_data.get('Recipient', '')
                if recipient and recipient != SAML_CONFIG['sp_acs_url']:
                    self.errors.append(
                        f'SubjectConfirmationData Recipient mismatch. Expected: {SAML_CONFIG["sp_acs_url"]}, Got: {recipient}'
                    )
                    return False

                not_on_or_after = conf_data.get('NotOnOrAfter')
                if not_on_or_after:
                    now = datetime.utcnow()
                    not_on_or_after_dt = datetime.fromisoformat(
                        not_on_or_after.replace('Z', '+00:00')
                    ).replace(tzinfo=None)
                    if now >= not_on_or_after_dt + timedelta(minutes=5):
                        self.errors.append(
                            f'SubjectConfirmationData has expired. NotOnOrAfter: {not_on_or_after}'
                        )
                        return False

        return True

    def extract_name_id(self, assertion):
        """Extract the NameID from the assertion."""
        subject = self._find(assertion, 'saml:Subject')
        if subject is None:
            return None

        name_id_elem = self._find(subject, 'saml:NameID')
        if name_id_elem is None:
            return None

        return {
            'value': name_id_elem.text,
            'format': name_id_elem.get('Format', ''),
            'sp_name_qualifier': name_id_elem.get('SPNameQualifier', ''),
            'name_qualifier': name_id_elem.get('NameQualifier', ''),
        }

    def extract_session_index(self, assertion):
        """Extract SessionIndex from AuthnStatement."""
        authn_statement = self._find(assertion, 'saml:AuthnStatement')
        if authn_statement is not None:
            return authn_statement.get('SessionIndex')
        return None

    def extract_attributes(self, assertion):
        """Extract user attributes from the AttributeStatement."""
        attributes = {}
        attr_statement = self._find(assertion, 'saml:AttributeStatement')
        if attr_statement is None:
            return attributes

        attr_elements = self._findall(attr_statement, 'saml:Attribute')
        for attr_elem in attr_elements:
            attr_name = attr_elem.get('Name', '')
            attr_friendly_name = attr_elem.get('FriendlyName', '')
            attr_values = []

            value_elements = self._findall(attr_elem, 'saml:AttributeValue')
            for value_elem in value_elements:
                if value_elem.text:
                    attr_values.append(value_elem.text)

            # Store by both Name and FriendlyName for convenience
            key = attr_friendly_name if attr_friendly_name else attr_name
            if len(attr_values) == 1:
                attributes[key] = attr_values[0]
            elif len(attr_values) > 1:
                attributes[key] = attr_values

            # Also store by full Name (often a URI)
            if attr_name and attr_name != key:
                if len(attr_values) == 1:
                    attributes[attr_name] = attr_values[0]
                elif len(attr_values) > 1:
                    attributes[attr_name] = attr_values

        return attributes

    def parse_and_validate(self):
        """Full parsing and validation pipeline."""
        result = {
            'valid': False,
            'errors': [],
            'user': None,
            'attributes': {},
            'name_id': None,
            'session_index': None,
        }

        # Validate response-level elements
        self.validate_response_status()
        self.validate_destination()
        self.validate_issuer()

        if self.errors:
            result['errors'] = self.errors
            return result

        # Get and validate assertion
        assertion = self.get_assertion()
        if assertion is None:
            result['errors'] = self.errors
            return result

        self.validate_assertion_conditions(assertion)
        self.validate_assertion_subject(assertion)

        if self.errors:
            result['errors'] = self.errors
            return result

        # Extract user information
        name_id = self.extract_name_id(assertion)
        session_index = self.extract_session_index(assertion)
        attributes = self.extract_attributes(assertion)

        if name_id is None:
            self.errors.append('No NameID found in assertion.')
            result['errors'] = self.errors
            return result

        # Build user object from attributes
        user = build_user_from_attributes(name_id, attributes)

        result['valid'] = True
        result['user'] = user
        result['attributes'] = attributes
        result['name_id'] = name_id
        result['session_index'] = session_index

        return result


def build_user_from_attributes(name_id, attributes):
    """Build a user dictionary from SAML attributes."""
    # Common attribute names from various IdPs
    email_keys = [
        'email', 'Email', 'emailAddress',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress',
        'urn:oid:0.9.2342.19200300.100.1.3',
        'mail',
    ]
    first_name_keys = [
        'firstName', 'FirstName', 'givenName', 'first_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname',
        'urn:oid:2.5.4.42',
    ]
    last_name_keys = [
        'lastName', 'LastName', 'surname', 'sn', 'last_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname',
        'urn:oid:2.5.4.4',
    ]
    display_name_keys = [
        'displayName', 'DisplayName', 'cn', 'display_name',
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name',
        'urn:oid:2.16.840.1.113730.3.1.241',
    ]
    groups_keys = [
        'groups', 'Groups', 'memberOf', 'role', 'roles',
        'http://schemas.xmlsoap.org/claims/Group',
        'http://schemas.microsoft.com/ws/2008/06/identity/claims/groups',
    ]
    department_keys = [
        'department', 'Department',
        'urn:oid:2.5.4.11',
    ]
    title_keys = [
        'title', 'Title', 'jobTitle',
        'urn:oid:2.5.4.12',
    ]

    def find_attribute(keys):
        for key in keys:
            if key in attributes:
                return attributes[key]
        return None

    email = find_attribute(email_keys) or name_id.get('value', '')
    first_name = find_attribute(first_name_keys) or ''
    last_name = find_attribute(last_name_keys) or ''
    display_name = find_attribute(display_name_keys) or f'{first_name} {last_name}'.strip()
    groups = find_attribute(groups_keys) or []
    department = find_attribute(department_keys) or ''
    title = find_attribute(title_keys) or ''

    if isinstance(groups, str):
        groups = [groups]

    user = {
        'name_id': name_id.get('value', ''),
        'email': email,
        'first_name': first_name,
        'last_name': last_name,
        'display_name': display_name if display_name else email,
        'groups': groups,
        'department': department,
        'title': title,
        'authenticated_at': datetime.utcnow().isoformat(),
    }

    return user


def create_user_session(user, session_index=None):
    """Create a Flask session for the authenticated user."""
    session_id = str(uuid.uuid4())

    session['user'] = user
    session['session_id'] = session_id
    session['saml_session_index'] = session_index
    session['authenticated'] = True
    session['login_time'] = datetime.utcnow().isoformat()
    session.permanent = True

    # Store in session registry
    user_sessions[session_id] = {
        'user': user,
        'session_index': session_index,
        'created_at': datetime.utcnow().isoformat(),
    }

    return session_id


def login_required(f):
    """Decorator to require SAML authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('saml_login'))
        return f(*args, **kwargs)
    return decorated_function


def generate_authn_request():
    """Generate a SAML AuthnRequest XML."""
    request_id = f'_id-{uuid.uuid4()}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    authn_request = f"""<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_sso_url']}"
    AssertionConsumerServiceURL="{SAML_CONFIG['sp_acs_url']}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>"""

    return request_id, authn_request


def generate_logout_request(name_id, session_index):
    """Generate a SAML LogoutRequest XML."""
    request_id = f'_id-{uuid.uuid4()}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    logout_request = f"""<samlp:LogoutRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_slo_url']}">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{name_id}</saml:NameID>
    <samlp:SessionIndex>{session_index or ''}</samlp:SessionIndex>
</samlp:LogoutRequest>"""

    return request_id, logout_request


