@app.route('/saml/login')
def saml_login():
    """Initiate SAML login by redirecting to IdP."""
    request_id, authn_request_xml = generate_authn_request()

    # Store request ID for validation
    session['pending_authn_request_id'] = request_id

    # Base64 encode the AuthnRequest
    encoded_request = base64.b64encode(authn_request_xml.encode('utf-8')).decode('utf-8')

    # For HTTP-POST binding, render a form that auto-submits
    return render_template_string("""
    <!DOCTYPE html>
    <html>
    <head><title>Redirecting to Identity Provider...</title></head>
    <body onload="document.forms[0].submit();">
        <h2>Redirecting to your Identity Provider...</h2>
        <form method="POST" action="{{ idp_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <input type="hidden" name="RelayState" value="{{ relay_state }}" />
            <noscript>
                <p>JavaScript is disabled. Click the button below to continue.</p>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    """, idp_url=SAML_CONFIG['idp_sso_url'], saml_request=encoded_request,
                                  relay_state=request.args.get('next', '/dashboard'))


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - processes SAML Response from IdP."""
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', '/dashboard')

    if not saml_response_b64:
        return jsonify({'error': 'No SAMLResponse found in request'}), 400

    try:
        parser = SAMLResponseParser(saml_response_b64)
        result = parser.parse_and_validate()
    except ET.ParseError as e:
        return jsonify({'error': f'Failed to parse SAML XML: {str(e)}'}), 400
    except Exception as e:
        return jsonify({'error': f'Error processing SAML response: {str(e)}'}), 500

    if not result['valid']:
        return render_template_string("""
        <!DOCTYPE html>
        <html>
        <head><title>SSO Login Failed</title></head>
        <body>
            <h1>SSO Login Failed</h1>
            <p>There was an error processing your SSO login:</p>
            <ul>
            {% for error in errors %}
                <li>{{ error }}</li>
            {% endfor %}
            </ul>
            <a href="{{ url_for('saml_login') }}">Try Again</a>
        </body>
        </html>
        """, errors=result['errors']), 401

    # Create user session
    user = result['user']
    session_index = result['session_index']
    create_user_session(user, session_index)

    return redirect(relay_state)


@app.route('/saml/sls', methods=['GET', 'POST'])
def saml_sls():
    """Single Logout Service - handles logout requests/responses from IdP."""
    if request.method == 'POST':
        saml_request_b64 = request.form.get('SAMLRequest')
        saml_response_b64 = request.form.get('SAMLResponse')
    else:
        saml_request_b64 = request.args.get('SAMLRequest')
        saml_response_b64 = request.args.get('SAMLResponse')

    if saml_response_b64:
        # IdP is responding to our logout request
        try:
            xml_bytes = base64.b64decode(saml_response_b64)
            root = ET.fromstring(xml_bytes.decode('utf-8'))
            status = root.find('.//samlp:Status/samlp:StatusCode', SAML_NAMESPACES)
            if status is not None and 'Success' in status.get('Value', ''):
                # Clear local session
                session_id = session.get('session_id')
                if session_id and session_id in user_sessions:
                    del user_sessions[session_id]
                session.clear()
                return redirect(url_for('index'))
        except Exception:
            pass

    if saml_request_b64:
        # IdP is requesting we log the user out (IdP-initiated SLO)
        try:
            xml_bytes = base64.b64decode(saml_request_b64)
            root = ET.fromstring(xml_bytes.decode('utf-8'))

            # Find SessionIndex to identify which session to terminate
            session_index_elem = root.find('.//samlp:SessionIndex', SAML_NAMESPACES)
            if session_index_elem is not None:
                target_session_index = session_index_elem.text
                # Find and remove matching sessions
                sessions_to_remove = [
                    sid for sid, sdata in user_sessions.items()
                    if sdata.get('session_index') == target_session_index
                ]
                for sid in sessions_to_remove:
                    del user_sessions[sid]

            # Clear current session
            session.clear()

            # Send LogoutResponse back to IdP
            response_id = f'_id-{uuid.uuid4()}'
            issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
            in_response_to = root.get('ID', '')

            logout_response = f"""<samlp:LogoutResponse
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{response_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_slo_url']}"
    InResponseTo="{in_response_to}">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
</samlp:LogoutResponse>"""

            encoded_response = base64.b64encode(logout_response.encode('utf-8')).decode('utf-8')

            return render_template_string("""
            <!DOCTYPE html>
            <html>
            <body onload="document.forms[0].submit();">
                <form method="POST" action="{{ idp_url }}">
                    <input type="hidden" name="SAMLResponse" value="{{ saml_response }}" />
                    <noscript><input type="submit" value="Continue" /></noscript>
                </form>
            </body>
            </html>
            """, idp_url=SAML_CONFIG['idp_slo_url'], saml_response=encoded_response)
        except Exception as e:
            session.clear()
            return redirect(url_for('index'))

    return redirect(url_for('index'))


